css:
/*【轻拟态▪】作者：易碎蝶*/

/*🍃←这个是可以调整的部分，以及用了【这个符号】*/

/* ====== 全局字体设置 ====== */
@import url("https://fontsapi.zeoseven.com/135/main/result.css");

body {
    font-family: "Judou Sans UI Hans";
    font-weight: normal;
}
/*———————— 顶栏背景 ————————*/
#top-bar {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 80px;
    pointer-events: none;
    z-index: 1000; /* 确保足够高的层级 */
    background: none;
    border: 0;
    box-shadow: none;
    overflow: visible;
}

#top-bar::before {
    content: "";
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 80px; /* 与#top-bar高度保持一致 */
    background: url("https://i.postimg.cc/6pqxfCcn/Image-2998688333470504.png") no-repeat center / cover;
    z-index: 1;
    pointer-events: auto; /* 允许交互 */
}

/* 添加媒体查询以适应不同设备 */
@media (max-width: 768px) {
    #top-bar {
        height: 1px; /* 移动端适当降低高度 */
    }

    #top-bar::before {
        height: 62px;
    }
}


/* —————面板背景图———— */
.drawer-content {
  background-image: url('https://i.postimg.cc/8CzKg2wx/Image-3005331852093900.png'); /* 示例图片URL */
  background-size: cover; 
  background-position: center; 
  background-repeat: no-repeat; 
  background-attachment: fixed; 
}

/*——————滑块——————*/

input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    width: 40px;
    height: 40px;
    background: transparent url('https://i.postimg.cc/pXFRwfzv/Image-3000798358904630.png') center/cover no-repeat;
    border: none;
    border-radius: 0;
    box-shadow: none;
    cursor: ew-resize;
    position: relative;
    z-index: 1;
}
/*⭕核心优化：移除阴影➕修改滑块颜色*/
.neo-range-slider {
    height: 7px !important;
    background: #ffffff !important;/*滑块颜色调整*/
    box-shadow: inset 0 0 5px rgb(138 140 141 / 50%) !important;
    cursor: ew-resize !important;
    z-index: 1;
}

input[type="range"] {
    filter: none; /* 移除阴影效果 */
}

/*——————最新消息箭头图标替换——————*/
/* ===== 隐藏原有字体图标 ===== */
.fa-chevron-right:before,
.fa-chevron-left:before,
.fa-arrow-right:before {
  content: "" !important;
  display: none !important; /* 双重保障隐藏图标 */
}

/* ===== 自定义箭头样式 ===== */
.fa-chevron-left,
.fa-chevron-right {
  display: inline-block;
  width: 30px;   /* 箭头图片宽度 */
  height: 30px;  /* 箭头图片高度 */
  background: center/contain no-repeat;
}

.fa-chevron-left {
  background-image: url('https://i.postimg.cc/0ygf2s43/Image-3002032253339473.png'); /* 左箭头URL */
}


.fa-chevron-right {
  background-image: url('https://i.postimg.cc/Jzj7kNzx/Image-3000816876050170.png'); /* 右箭头URL */
}

/* ===== 滑动计数器样式 ===== */
.swipes-counter {
  /* 文字样式 */
  color: var(--SmartThemeBodyColor);
  font-family: var(--mainFontFamily);
  font-size: 10px;
  font-weight: 540;

  /* 布局定位 */
  display: flex;
  justify-content: center;
  align-self: center;
  z-index: 3;

  /* 尺寸控制 */
  min-width: 0;
  height: var(--swipeCounterHeight); /* 高度变量 */
  padding: 0 30px;                 /* 水平内边距 */


  margin: 
    var(--counter-vertical, 0)    /* 垂直间距，默认0 */
    var(--counter-horizonta, 0);  /* 水平间距，默认0 */
  margin-bottom: var(--swipeCounterMargin); 
}

/*——————装饰层——————*/
/* /* ==============================================
 * 1. 🍃装饰层模块
 * ==============================================*/
/* 🍃上层装饰层 - 位于气泡上方 */
.mes::before {
  content: "";
  position: absolute;
  top: -60px; /* 上层装饰层【上下】(负值表示向上) */
  left: -9.5px; /* 上层装饰层【左右】 */
  width: 350px; /* 调整上层装饰层的【宽度/大小】 */
  height: 530px; /* 调整上层装饰层的【高度/大小】 */
  background-image: url('https://i.postimg.cc/VvMrZ2CX/Image-2932679377879108.png'); 
  background-size: contain; 
  background-repeat: no-repeat; 
  z-index: -2; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */

}



/* 🍃下层装饰层 - 位于气泡下方，跟随气泡尾部移动 */
.mes::after {
  content: "";
  position: absolute;
  bottom: -67px; /* 下层装饰层【上下】(负值表示向下) */
  right: -96.5px; /* 下层装饰层【左右】 */
  width: 510px; /* 调整下层装饰层的【宽度/大小】 */
  height: 122.6px; /* 调整下层装饰层的【高度/大小】 */
  background-image: url(''); 
  background-size: contain; 
  background-repeat: no-repeat; 
  z-index: -3; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */
}

/*——————🍃文本边距调整——————*/
/* 消息文本容器（可独立调整上下左右边距） */
.mes_text, 
.mes_reasoning {
    /* 基础样式 */
    font-weight: 500;
    line-height: calc(var(--mainFontSize) + .5rem);
    text-align: left; /* 文本左对齐 */
    overflow-wrap: anywhere;

    /* 🍃可独立调整的边距系统 */

    --top-padding: 0rem; /* 气泡顶部留白 */
    --bottom-padding: 2rem; /* 气泡底部留白 */
    --left-padding: 0rem; /* 气泡左边距 */
    --right-padding: 0.3rem; /* 气泡右边距 */

    padding-top: var(--top-padding);
    padding-bottom: var(--bottom-padding);
    padding-left: var(--left-padding);
    padding-right: var(--right-padding);

    max-width: 700%;
    margin: 0; /* 清除默认外边距 */

}






/*——————气泡设置——————*/

/* ==============================================
 * 1.🍃 气泡容器模块
 * ==============================================*/
.mes {
  color: #313131;
  z-index: -3;
  max-width: 330px;
  width: 400%;
  margin: 130px auto 0px;
  border-radius: 24px; /* 增加圆角实现柔和气泡效果 */


  box-shadow:
    8px 8px 16px rgba(0, 0, 0, 0.1),
    -8px -8px 16px rgba(255, 255, 255, 0.8),
    inset 2px 2px 5px rgba(255, 255, 255, 0.7),
    inset -2px -2px 5px rgba(0, 0, 0, 0.05);

  /* 边缘高光效果 */
  position: relative;
  overflow: visible;
  border: 1px solid rgba(255, 255, 255, 0.7); /* 浅色描边增强立体感 */
}
/*毛玻璃效果，让我们感谢@LiitleYE 老师*/
body.no-blur .mes {
background: rgba(250, 250, 252, 0.5); /* 半透明白色 */
  backdrop-filter: blur(30px) !important;
}

/* ==============================================
 * 头像装饰框修复版 (确保图片显示)
 * ============================================== */
/* 1. 确保头像容器有尺寸 */
.mesAvatarWrapper {
  position: absolute;
  top: -147px;
  left: 48.9%;
  transform: translateX(-50%);
  z-index: -1;

  /* 【新增】必须设置宽高 */
  width: 70px;  /* 头像宽度 */
  height: 70px; /* 头像高度 */
  overflow: visible; /* 允许装饰框超出 */
}

/* 2. 🍃装饰框核心样式 */
.mesAvatarWrapper::after {
  content: "";
  position: absolute;
  top: 44%;/* 【上下】 */
  left: 48%;/* 【左右】 */
  width: 130%;  /* 【框比头像大15%】 */
  height: 130%; /* 【框比头像高15%】 */

  /* 【修复关键】必须设置display */
  display: block; /* 或 inline-block */

  /* 【修复关键】确保背景图加载 */
  background-image: url('https://i.postimg.cc/Y9TL3thp/Image-2932676974052647.png');
  background-size: 100% 100%; /* 完全覆盖 */
  background-repeat: no-repeat;
  background-position: center;

  transform: translate(-50%, -50%);
  z-index: 1; /* 高于头像 */

  /* 调试辅助线 */
  /* border: 1px solid red; */
}

/* 3. 确保头像图片在装饰框下方 */
.mesAvatarWrapper img {
  position: relative;
  z-index: -1; /* 低于装饰框的20 */
}

/* ==============================================
 * 2. 🍃头像容器模块
 * ============================================== */
.mesAvatarWrapper {
  position: absolute;
  top: -54px;           /* 【控制头像在气泡上方的位置】 */
  left: 13%;            /* 【调整头像左右】 */
  transform: translateX(-50%);
  z-index: -1;
}

/* ==============================================
 * 3. 头像图像模块（可自定义形状）
 * ============================================== */
.mesAvatarWrapper .avatar {
  /* 🍃基础尺寸 - 可自定义修改 */
  width: 62px;           /* 头像宽度 */
  height: 62px;          /* 头像高度 */


  /* 外观样式 */
  overflow: hidden;
  border: 0px solid #fff;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0);
  transition: all 0.3s ease;

  /* 旋转效果 */
  transform: rotate(-0deg); /* 顺时针旋转 */
}


.mesAvatarWrapper .avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

/* ==============================================
 * 4. 🍃楼层显示
 * ============================================== */
.mes .mesIDDisplay {

    position: fixed;  
    top: 200;           
    left: 132%;        /* 【楼层左右】 */
    transform: translateX(-50%); 
    z-index: 999;    
    margin-top: -50px; /* 【楼层上下】 */

    /* 简约样式 */
    padding: 2px 12px;
    background: rgba(255, 255, 255, 0.0); /* 【这里可以填楼层显示的背景色，最后一个数字区调整透明度】 */
    border-radius: 4px;
    box-shadow: 90 2px px rgba(0, 0, 0, 0.1);

    /* 保留原有样式 */
    z-index: 2;
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 0.6);
    font-weight: 900;
    color: #aaaaaa; /* 【调整楼层显示的颜色】 */
}

/* 其他元素保持原有样式 */
.mes .mes_timer, .mes .tokenCounterDisplay {
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 1.9);
    font-weight: 600;
    text-align: center;
}
/* ==============================================
 * 5. 🍃基础信息位置调整【时间戳等】
 * ============================================== */
/* 消息块容器 */
.mes_block {
  position: relative;
  padding-top: 0px; /* 保持顶部留白 */
  overflow: visible; /* 确保子元素不被裁剪 */
}


/* 父容器设置相对定位 */
.mes_block {
  position: relative;
}

/* 角色名称 */

.mes_block .ch_name {
  position: relative;
  top: 14px; /* 添加单位px */
  left: 0px;
  max-width: calc(100% - 105px);
  min-height: -0px;
  z-index: 10;
  /* 文字优化 */
  font-size: 0.75em;
  font-weight: 200;
  letter-spacing: 0.9px;

}

.mes_block .ch_name {
  color: #aaaaaa; /* 角色昵称和编辑按钮颜色 */
}


/* 固定时间戳 */

.timestamp {
  color: #aaaaaa;
  position: absolute;
  top: 0;
    top: -46px;         /* 距父容器顶部的距离 */
  left: 66px;          /* 固定在父容器左侧 */
  pointer-events: none;
  font-size: 7px;
  font-weight: 900;
}

/* 可选：悬停时增加立体感 */
.timestamp:hover {
  box-shadow: 
    2px 2px 4px rgba(0, 0, 0, 0.08),
    -2px -2px 4px rgba(255, 255, 255, 0.9),
    inset 2px 2px 4px rgba(255, 255, 255, 0.9),
    inset -2px -2px 4px rgba(0, 0, 0, 0.08);
}

/* 编辑按钮容器优化 */
.mes_buttons {
  position: relative;
  top: -42px; /*上下*/
  left: 118px;/*左右*/
  z-index: 30;
  padding: 20px; /* 增加内边距 */
  min-height: 36px; /* 确保最小高度 */
  box-sizing: border-box; /* 包含内边距 */
}


.mes_edit_buttons {
    display: none;
    flex-direction: row;
    column-gap: 5px;
    float: right;
    cursor: pointer;
    padding-bottom: 50px;
    filter: none; /* 移除阴影效果 */
    transition: 0.3s ease-in-out;
opacity: 1 !important; /* 默认闲时透明度 */


    /* 垂直位置控制 */
    position: relative;       /* 确保定位生效 */
    top: -33px;              /* 负数上移 | 正数下移 | 单位可用px/rem/vh等 */

    /* 水平位置控制 */
    right: -90px;            /* 负数右移 | 正数左移 | 单位可用px/rem/vw等 */
}
.mes_edit_down.menu_button.fa-solid.fa-chevron-down.interactable.disabled {
    filter: none !important;
}

.mes_button, .extraMesButtons>div {
cursor: pointer;
transition: opacity 0.2s ease-in-out;
    /* 移除原阴影并添加白色阴影 */
    filter: drop-shadow(0px 0px 0px #ffffff) !important;
    /* 添加颜色设置为白色 */
    color: #000000 !important;
opacity: 0.4 !important; /* 默认闲时透明度 */
}
/* ==============================================
 * 🕒 计时器 & 🔤 字符计数显示组件
 * ============================================== */

.mes {
  position: relative; /* 创建定位上下文 */
}

/* 通用样式 */
.mes .mes_timer,
.mes .tokenCounterDisplay {
  position: fixed; /* 使用固定定位确保不被遮挡 */
  z-index: 2147483647; /* 最高层级 (32位整数最大值) */
  cursor: default;
  opacity: 0.7;
  font-size: calc(var(--mainFontSize) * 0.6);
  font-weight: 900;
  text-align: center;
  padding: 0px 0px;
  border-radius: 0px;
  background: rgba(30, 30, 30, 0.0); /* 半透明白色背景 */
  backdrop-filter: blur(0px); /* 毛玻璃效果 */
  box-shadow: 0 2px 8px rgba(0,0,0,0.0);

  /* 默认位置 - 顶部居中 */
  top: 240px;
  left: 50%;
  transform: translateX(-50%);

  /* 颜色变量 - 便于单独修改 */
  --timer-color: #aaaaaa;
  --counter-color: #aaaaaa;
}

/* 单独控制计时器 */
.mes .mes_timer {
  z-index: 2;
  /* 位置调整 */
  top: var(--timer-top, 14px);  /* 【🍃计时器上下】 */
  left: var(--timer-left, 315%);/*【🍃计时器左右】*/
  transform: translateX(var(--timer-translate, -50%));

  /* 颜色控制 */
  color: var(--timer-color, #aaaaaa);
}

/* 单独控制字符计数 */
.mes .tokenCounterDisplay {
  z-index: 2;
  /* 位置调整 */
  top: var(--counter-top, 14px); /* 【🍃字符上下】 */
  left: var(--counter-left, 212%);/* 【🍃字符左右】 */
  transform: translateX(var(--counter-translate, -0%));

  /* 颜色控制 */
  color: var(--counter-color, #aaaaaa);
}
/* ==============================================
 * 🧠 外显思维链位置与颜色调整
 * ============================================== */
.mes_reasoning_header {
  position: absolute;
  z-index: 9999;
  top: -20px;
  left: 33%;
  transform: translateX(-50%);
  cursor: pointer;
  user-select: none;
  font-size: calc(var(--mainFontSize) * 0.85); /* 动态字体大小 */
  opacity: 0.9;
  transition: all 0.3s ease;  

  /* 轻拟态核心样式 */
  padding: 4px 10px;          /* 内边距 */
  background: rgba(250, 250, 252, 0.9); /* 半透明白灰背景 */
  border-radius: 8px;
  box-shadow:
    4px 4px 8px rgba(0, 0, 0, 0.08),   
    -4px -4px 8px rgba(255, 255, 255, 0.9), 
    inset 1px 1px 2px rgba(255, 255, 255, 0.8), 
    inset -1px -1px 2px rgba(0, 0, 0, 0.05); 
}

/* 悬停效果增强 */
.mes_reasoning_header:hover {
  background: rgba(240, 242, 245, 0.95); /* 加深背景色 */

  box-shadow:
    5px 5px 10px rgba(0, 0, 0, 0.1),
    -5px -5px 10px rgba(255, 255, 255, 1),
    inset 2px 2px 3px rgba(255, 255, 255, 0.9),
    inset -2px -2px 3px rgba(0, 0, 0, 0.07);
}

/* 标题文字样式 */
.mes_reasoning_header_title {
  position: relative;
  display: inline-block;
  top: 0px;                   /* 垂直位置 */
  left: -9px;                 /* 向左偏移 */
  color: #4A5568;             /* 深灰文字（增加可读性） */
  text-shadow: 0 1px 1px rgba(255, 255, 255, 0.8); /* 强化高光 */
}

/* 推理内容主体 */
.mes_reasoning {
  position: relative;         /* 相对定位 */
  top: -180px;                /* 垂直位置 */
  display: block;
  margin: 135px 0px -170px;            /* 上下外边距 */

  /* 轻拟态核心样式 */
  border-left: 2px solid #AbAbAb; /* 浅灰左侧装饰条 */
  color: #4A5568;     
  background: rgba(248, 250, 252, 0.85); /* 半透明白灰背景 */
  border-radius: 0 12px 12px 0; 

  padding: 15px;              /* 内容内边距 */


  box-shadow:
    6px 6px 12px rgba(0, 0, 0, 0.07),   /* 右下柔和阴影 */
    -6px -6px 12px rgba(255, 255, 255, 0.85),
    inset 3px 3px 6px rgba(255, 255, 255, 0.7), 
    inset -3px -3px 6px rgba(0, 0, 0, 0.04); 
}
.mes_reasoning_header_title {
  /* 隐藏原始文本 */
  font-size: 0; 
  color: transparent; 
}

.mes_reasoning_header_title::before {
  /*⭕️思维链文字diy */
  content: "·𝑏𝑒 𝑜𝑟𝑖𝑔𝑖𝑛𝑎𝑙 ♪。";
  font-size: 9px; /* 字号 */
  color: #5a5a5a;      /* 颜色 */
}

/*—— 输入框提示词编辑（感谢墨千尾老师） ——*/

#nonQRFormItems {
    position: relative;
}
#send_textarea::placeholder {
    color: transparent !important;
    text-shadow: none !important; /* 移除可能存在的文字阴影 */
}
#nonQRFormItems:has(#send_textarea:placeholder-shown)::before {
    content: "˚. ☽ 愛という夢に迷った ༉‧₊˚.    "; /* 文字 */
    color: #e0e0e0; /* 颜色 */
    left: 100px; /* 左右位置 */
    position: absolute; 
    top: 52%; /* 上下位置 */
    transform: translateY(-50%); 

    font-style: oblique; /* 字体样式：可以改为 normal (正常) 或 oblique (倾斜) */
    font-size: 0.4em;  /* 字体大小 */
    pointer-events: none; 
    z-index: 10; /* 确保它显示在最上层 */
    white-space: nowrap; 
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: calc(100% - 30px); 
}

/* ===== 基础图标样式 ===== */
.drawer-icon:not(.openIcon) { 
  opacity: 0 !important; /*未选时透明度*/
}

/* 通用图标替换样式 */
.drawer-icon {
  background: url('https://i.postimg.cc/RVkVhs4q/Image-3000814949244939.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

.drawer-icon::before {
  display: none !important;
}
/* ===== 特定图标覆盖 ===== */
/* AI响应配置 */
#leftNavDrawerIcon {
  background-image: url('https://i.postimg.cc/0ygf2s43/Image-3002032253339473.png') !important;
}

/* API连接 */
#API-status-top::before { display: none !important; }
#API-status-top {
  background: url('https://i.postimg.cc/Jzj7kNzx/Image-3000816876050170.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
  font-size: 0 !important;
}

/* AI回复格式化 */
.drawer-icon.fa-font::before { display: none !important; }
.drawer-icon.fa-font {
  background: ur1('https://i.postimg.cc/2883RsYC/Image-2643185420880930.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

/* 世界信息 */
