        5px 5px 10px rgba(0, 0, 0, 0.05);            /* 外右下阴影 */

    /* 聚焦状态 */
    &:focus {
        box-shadow: 
            inset -3px -3px 6px rgba(255, 255, 255, 0.7),
            inset 3px 3px 6px rgba(0, 0, 0, 0.07),
            -5px -5px 10px rgba(255, 255, 255, 0.7),
            5px 5px 10px rgba(0, 0, 0, 0.1);
    }

    &::placeholder {
        color: #a0aec0; /* 浅蓝灰占位符 */
    }

    /* 滚动条美化 */
    scrollbar-width: thin;
    scrollbar-color: #c1d0d7 #eaf2f9;

    &::-webkit-scrollbar {
        width: 6px;
        background: #eaf2f9;           
    }

    &::-webkit-scrollbar-thumb {
        background: #c1d0d7;
        border-radius: 3px;
    }
}

